using System;
using System.Data.SqlClient;
using System.IO;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

public static class ReportingFunction
{
    [FunctionName("ReportingFunction")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        string connectionString = Environment.GetEnvironmentVariable("AzureSqlConnectionString");
        string tableName = Environment.GetEnvironmentVariable("TableName");

        if (string.IsNullOrEmpty(connectionString) || string.IsNullOrEmpty(tableName))
        {
            return new BadRequestObjectResult("Missing connection string or table name.");
        }

        string queryBuilder = $"SELECT * FROM {tableName} WHERE 1=1";
        var parameters = req.Query;

        foreach (var param in parameters)
        {
            if (!string.IsNullOrEmpty(param.Value))
            {
                queryBuilder += $" AND {param.Key} = @{param.Key}";
            }
        }

        using (SqlConnection connection = new SqlConnection(connectionString))
        {
            try
            {
                await connection.OpenAsync();
                SqlCommand command = new SqlCommand(queryBuilder, connection);

                foreach (var param in parameters)
                {
                    if (!string.IsNullOrEmpty(param.Value))
                    {
                        command.Parameters.AddWithValue($"@{param.Key}", param.Value);
                    }
                }

                SqlDataReader reader = await command.ExecuteReaderAsync();

                using (StringWriter sw = new StringWriter())
                {
                    while (await reader.ReadAsync())
                    {
                        for (int i = 0; i < reader.FieldCount; i++)
                        {
                            sw.Write(reader[i].ToString());
                            if (i < reader.FieldCount - 1)
                                sw.Write(",");
                        }
                        sw.WriteLine();
                    }

                    return new OkObjectResult(sw.ToString());
                }
            }
            catch (Exception ex)
            {
                log.LogError(ex, "Error executing SQL query.");
                return new StatusCodeResult(500);
            }
        }
    }
}